import React, { useState, useEffect, useRef, useCallback } from "react";
import { useAuth } from "../context/AuthContext";
import UserPanel from "../components/UserPanel";
import LiveFeed from "../components/LiveFeed";
import DetectionHistory from "../components/DetectionHistory";
import StatsPanel from "../components/StatsPanel";
import {
  startDetection,
  stopDetection,
  getDetections,
  getStats,
  getDetectionStatus,
  WS_URL,
} from "../services/api";
import "./Dashboard.css";

const TABS = [
  { id: "user", label: "User Dashboard", icon: "👤" },
  { id: "feed", label: "Live Detection", icon: "📹" },
  { id: "history", label: "History Panel", icon: "📋" },
  { id: "stats", label: "Statistics", icon: "📊" },
];

export default function Dashboard() {
  const { user, logout } = useAuth();
  const [activeTab, setActiveTab] = useState("user");
  const [running, setRunning] = useState(false);
  const [frame, setFrame] = useState(null);
  const [fps, setFps] = useState(0);
  const [history, setHistory] = useState([]);
  const [stats, setStats] = useState({
    total_detections: 0,
    object_counts: {},
    timeline: [],
  });
  const wsRef = useRef(null);
  const reconnectTimer = useRef(null);

  /* ── Fetch initial data ──────────────────────────────────────────── */
  useEffect(() => {
    getDetectionStatus()
      .then((r) => setRunning(r.data.running))
      .catch(() => {});
    getDetections(50)
      .then((r) => setHistory(r.data.detections))
      .catch(() => {});
    getStats()
      .then((r) => setStats(r.data))
      .catch(() => {});
  }, []);

  /* ── WebSocket connection ────────────────────────────────────────── */
  const connectWs = useCallback(() => {
    if (wsRef.current) return;
    const ws = new WebSocket(WS_URL);
    wsRef.current = ws;

    ws.onopen = () => console.log("[WS] connected");

    ws.onmessage = (evt) => {
      const msg = JSON.parse(evt.data);
      if (msg.type === "detection") {
        setFrame(msg.frame);
        setFps(msg.fps);
        if (msg.detections?.length) {
          setHistory((prev) => [...msg.detections, ...prev].slice(0, 200));
          setStats((prev) => {
            const newCounts = { ...prev.object_counts };
            msg.detections.forEach((d) => {
              newCounts[d.object_name] = (newCounts[d.object_name] || 0) + 1;
            });
            return {
              ...prev,
              total_detections: prev.total_detections + msg.detections.length,
              object_counts: newCounts,
            };
          });
        }
      }
    };

    ws.onclose = () => {
      wsRef.current = null;
      reconnectTimer.current = setTimeout(connectWs, 2000);
    };
    ws.onerror = () => ws.close();
  }, []);

  useEffect(() => {
    connectWs();
    return () => {
      clearTimeout(reconnectTimer.current);
      if (wsRef.current) wsRef.current.close();
    };
  }, [connectWs]);

  /* Keep WS alive */
  useEffect(() => {
    const id = setInterval(() => {
      if (wsRef.current?.readyState === WebSocket.OPEN) {
        wsRef.current.send("ping");
      }
    }, 25000);
    return () => clearInterval(id);
  }, []);

  /* Refresh stats periodically */
  useEffect(() => {
    const id = setInterval(() => {
      getStats()
        .then((r) => setStats(r.data))
        .catch(() => {});
    }, 10000);
    return () => clearInterval(id);
  }, []);

  /* ── Controls ────────────────────────────────────────────────────── */
  const handleStart = async () => {
    await startDetection();
    setRunning(true);
    setActiveTab("feed");
  };
  const handleStop = async () => {
    await stopDetection();
    setRunning(false);
    setFrame(null);
  };

  /* ── Render active panel ─────────────────────────────────────────── */
  const renderPanel = () => {
    switch (activeTab) {
      case "user":
        return <UserPanel stats={stats} running={running} fps={fps} />;
      case "feed":
        return <LiveFeed frame={frame} running={running} />;
      case "history":
        return <DetectionHistory history={history} />;
      case "stats":
        return <StatsPanel stats={stats} />;
      default:
        return null;
    }
  };

  return (
    <div className="app-layout">
      {/* ── Sidebar ──────────────────────────────────────────────────── */}
      <aside className="sidebar">
        <div className="sidebar__brand">
          <span className="sidebar__logo">&#128065;</span>
          <span className="sidebar__name">AI Detection</span>
        </div>

        <nav className="sidebar__nav">
          {TABS.map((tab) => (
            <button
              key={tab.id}
              className={`sidebar__link ${activeTab === tab.id ? "active" : ""}`}
              onClick={() => setActiveTab(tab.id)}
            >
              <span className="sidebar__icon">{tab.icon}</span>
              <span className="sidebar__text">{tab.label}</span>
            </button>
          ))}
        </nav>

        <div className="sidebar__footer">
          <div className="sidebar__user">
            <div className="sidebar__user-avatar">
              {user?.username?.charAt(0).toUpperCase() || "U"}
            </div>
            <div className="sidebar__user-info">
              <span className="sidebar__user-name">{user?.username}</span>
              <span className="sidebar__user-email">{user?.email}</span>
            </div>
          </div>
          <button className="sidebar__logout" onClick={logout}>
            Logout
          </button>
        </div>
      </aside>

      {/* ── Main content ─────────────────────────────────────────────── */}
      <div className="main-content">
        {/* Header */}
        <header className="topbar">
          <div className="topbar__left">
            <h1 className="topbar__title">
              {TABS.find((t) => t.id === activeTab)?.icon}{" "}
              {TABS.find((t) => t.id === activeTab)?.label}
            </h1>
          </div>
          <div className="topbar__right">
            <span className={`status-dot ${running ? "active" : ""}`} />
            <span className="status-label">
              {running ? "Detection Active" : "Idle"}
            </span>
            {running ? (
              <button className="btn btn--red" onClick={handleStop}>
                Stop Detection
              </button>
            ) : (
              <button className="btn btn--green" onClick={handleStart}>
                Start Detection
              </button>
            )}
          </div>
        </header>

        {/* Panel */}
        <section className="panel-area">{renderPanel()}</section>
      </div>
    </div>
  );
}
